# These fall in the .in_labels jump table data. Let's look for the nearest FUNC symbols 
# preceding these addresses using all symbol tables
aarch64-linux-gnu-readelf -sW /tmp/libmonosgen-2.0.so.dbg | awk '
$4 == "FUNC" || $4 == "NOTYPE" {
  addr = strtonum("0x"$2)
  name = $NF
  if (addr > 0 && addr <= 0x2f4b20) { f1_addr = addr; f1_name = name }
  if (addr > 0 && addr <= 0x2f4c84) { f2_addr = addr; f2_name = name }
}
END {
  printf "Nearest func before 0x2f4b20: %s at 0x%x (+0x%x)\n", f1_name, f1_addr, 0x2f4b20 - f1_addr
